mapper.select:
SELECT e.*, c.course_name, a.nickname as teacher_name, u.nickname as student_name FROM stat_teaching_evaluation e LEFT JOIN edu_course c ON e.course_id = c.course_id LEFT JOIN edu_teacher t ON e.teacher_id = t.teacher_id LEFT JOIN edu_student s ON e.student_id = s.student_id LEFT JOIN sys_user a ON t.user_id = a.user_id LEFT JOIN sys_user u ON s.user_id = u.user_id
AND t.nickname LIKE CONCAT('%', #{teacherName}, '%')
AND e.evaluate_time >= #{startTime}
AND e.evaluate_time <= #{endTime}
ORDER BY e.evaluate_time DESC
